// Enter the world where both runs' ensures hold; that is the antecedent of
// the postcondition's implication, so all reasoning below is conditional on it.
if post1_self_.wf() && post1_self_@ == Set::<usize>::empty()
    && post2_self_.wf() && post2_self_@ == Set::<usize>::empty()
{
    // ArraySet::wf contains:
    //   forall|i:usize| 0 <= i < N && self.data@[i as int] ==> self.set@.contains(i)
    // The two ensures conjuncts give two such foralls (one per run) whose
    // triggers (`data@[i as int]`, `set@.contains(i)`) mention DIFFERENT
    // `self`s -- that's the z3 unknown. Re-assert each one explicitly so
    // both get instantiated against the same outer `i`.
    assert forall|i: usize| 0 <= i < N implies
        post1_self_.data@[i as int] == false by {
        // view == Set::empty(), and Set::empty().contains(_) is axiomatically false,
        // so the wf-implication forces !data@[i as int].
        assert(!post1_self_@.contains(i));
        assert(!post1_self_.set@.contains(i));
    };
    assert forall|i: usize| 0 <= i < N implies
        post2_self_.data@[i as int] == false by {
        assert(!post2_self_@.contains(i));
        assert(!post2_self_.set@.contains(i));
    };

    // Length of data@ comes from data.wf() (the first conjunct of ArraySet::wf).
    assert(post1_self_.data@.len() == N);
    assert(post2_self_.data@.len() == N);

    // Pointwise equality on int indices, using the per-usize facts above.
    assert forall|i: int| 0 <= i < N implies
        post1_self_.data@[i] == post2_self_.data@[i] by {
        let iu = i as usize;
        assert(post1_self_.data@[iu as int] == false);
        assert(post2_self_.data@[iu as int] == false);
    };

    // Sequence extensionality lifts pointwise equality to view equality on data.
    assert(post1_self_.data@ =~= post2_self_.data@);
    assert(post1_self_.data.seq@ =~= post2_self_.data.seq@);

    // The set-view (and hence the .set@ ghost) is equal (both Set::empty()).
    assert(post1_self_@ =~= post2_self_@);
    assert(post1_self_.set@ =~= post2_self_.set@);

    // From wf: self.len == self.set@.len() == Set::empty().len() == 0.
    assert(post1_self_.set@.len() == 0);
    assert(post2_self_.set@.len() == 0);
    assert(post1_self_.len == 0);
    assert(post2_self_.len == 0);
    assert(post1_self_.len == post2_self_.len);
}
